// ───────────────────── Continuous-batch decode scheduler ─────────────────────
// MOONSHINE_CONTINUOUS_BATCH: batch concurrent /generate requests through
// `decode_step_batch` (the parity-verified kernel) — ONE weight read per wave (the
// read-bound capture). Flag OFF (default) → handle_generate's existing lock-and-loop
// runs, byte-identical. v1 covers greedy/temperature + EOS/max_new_tokens on the
// llama/mistral pipeline; terminal_prosody / resume / non-llama fall back to the
// serial path (see the handle_generate gate). Spec: FAT_STATION_CONTINUOUS_BATCH.md.

/// One pending or in-flight generation on the batched wave.
struct BatchJob {
    tokens: Vec<u32>,
    max_new_tokens: usize,
    temperature: f32,
    seed: Option<u64>,
    reply: Sender<Result<Vec<u32>, String>>,
}

/// A lane of the wave hosting one `BatchJob`. `feed_count` walks the prompt (KV seed)
/// then the generated tokens; the lane retires at EOS / `max_new_tokens`.
struct BatchLane {
    job: BatchJob,
    feed_count: usize,
    generated: Vec<u32>,
    last_token: u32,
    rng: Option<fastrand::Rng>,
}

/// Submission queue feeding the single continuous-batch decode thread.
struct BatchScheduler {
    pending: Mutex<VecDeque<BatchJob>>,
    cv: Condvar,
}

impl BatchScheduler {
    fn new() -> Self {
        Self {
            pending: Mutex::new(VecDeque::new()),
            cv: Condvar::new(),
        }
    }
    /// Enqueue a job and wake the decode thread.
    fn submit(&self, job: BatchJob) {
        self.pending.lock().unwrap().push_back(job);
        self.cv.notify_one();
    }
}

/// Process-global continuous-batch scheduler, set once at startup IFF
/// MOONSHINE_CONTINUOUS_BATCH is on AND the pipeline is llama. `None` everywhere else
/// → `/generate` stays on the serial lock-and-loop path (byte-identical to today).
static BATCH_SCHEDULER: std::sync::OnceLock<Arc<BatchScheduler>> = std::sync::OnceLock::new();

fn batch_scheduler() -> Option<&'static Arc<BatchScheduler>> {
    BATCH_SCHEDULER.get()
}

/// `MOONSHINE_CONTINUOUS_BATCH=1|true` enables the batched `/generate` path.
fn continuous_batch_enabled() -> bool {
    std::env::var("MOONSHINE_CONTINUOUS_BATCH")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false)
}

/// Greedy (T=0) or temperature-multinomial draw of one token — mirrors
/// `handle_generate`'s sampler verbatim so batched output is token-identical.
fn batch_sample(logits: &[f32], temperature: f32, rng: Option<&mut fastrand::Rng>) -> u32 {
    let argmax = |l: &[f32]| -> u32 {
        l.iter()
            .enumerate()
            .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
            .map(|(i, _)| i as u32)
            .unwrap_or(0)
    };
    if temperature <= 0.0 {
        return argmax(logits);
    }
    let max_logit = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let inv_t = 1.0_f32 / temperature;
    let mut sum = 0.0_f32;
    let exps: Vec<f32> = logits
        .iter()
        .map(|&l| {
            let e = ((l - max_logit) * inv_t).exp();
            sum += e;
            e
        })
        .collect();
    if !sum.is_finite() || sum <= 0.0 {
        return argmax(logits);
    }
    let u = match rng {
        Some(r) => r.f32(),
        None => fastrand::f32(),
    } * sum;
    let mut cum = 0.0_f32;
    for (i, &e) in exps.iter().enumerate() {
        cum += e;
        if cum >= u {
            return i as u32;
        }
    }
    (exps.len().saturating_sub(1)) as u32
}

/// The fixed-width wave of decode lanes — the testable core (no thread, no `Station`).
/// `decode_step_batch` reads each layer's weight ONCE for the whole wave; per-lane
/// attention + sampling diverge. Drive it with `admit` then `step` until `!any_live()`.
struct BatchWave {
    seq_kv: Vec<KVCache>,
    positions: Vec<usize>,
    lanes: Vec<Option<BatchLane>>,
    /// Live lanes are kept CONTIGUOUS at `[0..n_live)` so each step decodes exactly the
    /// live count — no wasted empty-lane dots (the weight read is amortized either way,
    /// but the per-lane compute should track the real load). Compacted on retire.
    n_live: usize,
    capacity: usize,
    vocab: usize,
}

impl BatchWave {
    fn new(pipeline: &NativeLlamaPipeline, capacity: usize) -> Self {
        let (n_layers, n_kv, head_dim, max_seq) = pipeline.batch_lane_dims();
        BatchWave {
            seq_kv: (0..capacity).map(|_| KVCache::new(n_layers, n_kv, head_dim, max_seq)).collect(),
            positions: vec![0usize; capacity],
            lanes: (0..capacity).map(|_| None).collect(),
            n_live: 0,
            capacity,
            vocab: pipeline.vocab_size(),
        }
    }

    fn any_live(&self) -> bool {
        self.n_live > 0
    }

    fn has_free_lane(&self) -> bool {
        self.n_live < self.capacity
    }

    /// Admit `job` into the next free lane (`n_live`), clearing its KV slab (the per-lane
    /// reset that makes lane re-use correct). Returns the job back if the wave is full.
    fn admit(&mut self, job: BatchJob) -> Option<BatchJob> {
        if self.n_live >= self.capacity {
            return Some(job);
        }
        let k = self.n_live;
        self.seq_kv[k].clear();
        self.positions[k] = 0;
        let rng = job.seed.map(fastrand::Rng::with_seed);
        self.lanes[k] = Some(BatchLane {
            job,
            feed_count: 0,
            generated: Vec::new(),
            last_token: 0,
            rng,
        });
        self.n_live += 1;
        None
    }

    /// Fail every live lane with `e` (kernel error) and drain the wave.
    fn fail_all(&mut self, e: &str) {
        for k in 0..self.n_live {
            if let Some(lane) = self.lanes[k].take() {
                let _ = lane.job.reply.send(Err(e.to_string()));
            }
        }
        self.n_live = 0;
    }

    /// One batched decode step over the `n_live` live lanes: the weight read amortized
    /// across the wave, then per-lane sample / retire. Retired lanes `reply.send(Ok)` and
    /// are compacted out so the live set stays contiguous. `Err` only on kernel failure.
    fn step(&mut self, pipeline: &mut NativeLlamaPipeline) -> Result<(), String> {
        let n = self.n_live;
        if n == 0 {
            return Ok(());
        }
        // Gather one input token per live lane (prompt during prefill, else last sampled).
        let mut tokens = vec![0u32; n];
        for k in 0..n {
            let lane = self.lanes[k].as_ref().expect("live lane present");
            tokens[k] = if lane.feed_count < lane.job.tokens.len() {
                lane.job.tokens[lane.feed_count]
            } else {
                lane.last_token
            };
        }
        // THE FANOUT: one weight read serves the whole wave (only the live lanes).
        let logits = pipeline
            .decode_step_batch(&mut self.seq_kv[0..n], &mut self.positions[0..n], &tokens)
            .map_err(|e| format!("decode_step_batch: {}", e))?;
        // Sample each live lane; mark which retire this step.
        let mut retire = vec![false; n];
        for k in 0..n {
            let lane = self.lanes[k].as_mut().expect("live lane present");
            lane.feed_count += 1;
            if lane.feed_count < lane.job.tokens.len() {
                continue; // still seeding KV from the prompt; nothing to emit yet
            }
            let off = k * self.vocab;
            let tok =
                batch_sample(&logits[off..off + self.vocab], lane.job.temperature, lane.rng.as_mut());
            lane.generated.push(tok);
            lane.last_token = tok;
            retire[k] = tok == 2 || tok == 151_643 || lane.generated.len() >= lane.job.max_new_tokens;
        }
        // Compact: send replies for retired lanes; swap the survivors down so the live
        // set stays `[0..n_live)` (slab + position + lane move together via swap).
        let mut w = 0;
        for r in 0..n {
            if retire[r] {
                if let Some(lane) = self.lanes[r].take() {
                    let _ = lane.job.reply.send(Ok(lane.generated));
                }
            } else {
                if w != r {
                    self.lanes.swap(w, r);
                    self.seq_kv.swap(w, r);
                    self.positions.swap(w, r);
                }
                w += 1;
            }
        }
        self.n_live = w;
        Ok(())
    }
}

/// The continuous-batch decode thread: owns the pipeline, drives a `BatchWave`, pulling
/// jobs from the scheduler queue. Spawned once at startup when MOONSHINE_CONTINUOUS_BATCH
/// is on; llama/mistral pipeline only (decode_step_batch is the transformer kernel).
fn batch_decode_loop(station: Arc<Station>, sched: Arc<BatchScheduler>, capacity: usize) {
    let mut wave = {
        let mut p = station.pipeline.lock().unwrap();
        match p.as_llama_mut() {
            Some(lp) => BatchWave::new(lp, capacity),
            None => {
                eprintln!("[fat-station] continuous-batch: non-llama pipeline; decode thread idle");
                return;
            }
        }
    };
    loop {
        // Admit pending jobs into free lanes (block while fully idle).
        {
            let mut pending = sched.pending.lock().unwrap();
            while pending.is_empty() && !wave.any_live() {
                pending = sched.cv.wait(pending).unwrap();
            }
            while wave.has_free_lane() {
                match pending.pop_front() {
                    Some(job) => {
                        wave.admit(job);
                    }
                    None => break,
                }
            }
        }
        // One batched step; on kernel error, fail every live lane and continue.
        let res = {
            let mut p = station.pipeline.lock().unwrap();
            match p.as_llama_mut() {
                Some(lp) => wave.step(lp),
                None => Err("continuous-batch: pipeline no longer llama".to_string()),
            }
        };
        if let Err(e) = res {
            wave.fail_all(&e);
        }
    }
}

fn handle_generate(station: &Station, mut req: Request) {
    if !matches!(station.role, Role::Both | Role::Entry) {
        let _ = req.respond(error_response(
            "/generate only available on role=both|entry",
            404,
        ));
        return;
    }
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let json: serde_json::Value = match serde_json::from_slice(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("bad JSON: {}", e), 400));
            return;
        }
    };
    let tokens: Vec<u32> = match json.get("tokens").and_then(|v| v.as_array()) {
        Some(arr) => arr
            .iter()
            .filter_map(|v| v.as_u64().map(|n| n as u32))
            .collect(),
        None => {
            let _ = req.respond(error_response("missing field: tokens (u32 array)", 400));
            return;
        }
    };
    let max_new_tokens = json
        .get("max_new_tokens")
        .and_then(|v| v.as_u64())
        .unwrap_or(1) as usize;
    // NOTE: previously this was clamped to NATIVE_BATCH_CAPACITY (=8). That
    // cap was a misread of the kernel's prefill chunk limit — it applies to
    // a SINGLE forward_range_chunk call (how many tokens flow through the
    // batched matmul at once), not to the overall number of decode steps.
    // Capping max_new_tokens silently truncated all longer outputs at 8.
    //
    // Sampling temperature. T == 0 → argmax (deterministic greedy decode).
    // T > 0 → softmax-with-temperature multinomial sample. Negative values
    // are clamped to 0 (treated as greedy) so the API stays forgiving.
    let temperature = json
        .get("temperature")
        .and_then(|v| v.as_f64())
        .map(|t| if t.is_finite() { t as f32 } else { 0.0 })
        .map(|t| if t < 0.0 { 0.0 } else { t })
        .unwrap_or(0.0);
    // Optional explicit seed for reproducibility. If absent, the global
    // thread-local RNG (`fastrand::f32()`) is used, which is non-deterministic
    // across requests.
    let sampling_seed: Option<u64> = json.get("seed").and_then(|v| v.as_u64());
    let mut sampling_rng: Option<fastrand::Rng> = sampling_seed.map(fastrand::Rng::with_seed);
    // RESUME plane (SSM/RWKV-7 O(1) checkpoint resume-anywhere). When
    // `resume:true`, the recurrent state is NOT reset — the caller is expected to
    // have just restored it via POST /ssm-state/load — and the supplied `tokens`
    // are fed starting at `start_pos` (the position the saved state left off at),
    // so decode CONTINUES the loaded state instead of re-prefilling from 0. This
    // makes "checkpoint on instance A -> load on a fresh instance B -> identical
    // continuation" expressible over the HTTP API for rwkv7 (which has no
    // /decode-next | /sample-next fast path). Default false = legacy behavior.
    let resume = json.get("resume").and_then(|v| v.as_bool()).unwrap_or(false);
    let start_pos = json.get("start_pos").and_then(|v| v.as_u64()).unwrap_or(0) as usize;
    let terminal_prosody = parse_terminal_prosody(&json);
    // Sovereign-sieve semantic KEY: when true, return the LAST prompt token's post-all-layers
    // residual (pre-lm_head) alongside the generation — ONE forward serves both the cache key
    // and the answer (no separate /hidden-embed round-trip, no double prefill). Default false →
    // response byte-identical. Forces the serial path (the continuous-batch scheduler does not
    // surface per-request hidden state), so it's opt-in per request.
    let return_hidden = json
        .get("return_hidden")
        .and_then(|v| v.as_bool())
        .unwrap_or(false);

    let num_layers = station.layers.1.saturating_sub(station.layers.0);
    let t0 = std::time::Instant::now();
    let mut generated: Vec<u32> = Vec::with_capacity(max_new_tokens);
    let mut terminal_tail_state = terminal_prosody
        .as_ref()
        .map(|p| p.tail_state)
        .unwrap_or(TerminalTailState::OpenClause);

    if tokens.is_empty() {
        let _ = req.respond(error_response("tokens must be non-empty", 400));
        return;
    }

    // ── Continuous-batch fast path (MOONSHINE_CONTINUOUS_BATCH) ──────────────
    // Hand plain greedy/temperature decodes to the shared scheduler, which batches
    // concurrent /generate through decode_step_batch (one weight read per wave). Only
    // when the scheduler is live (flag on + llama pipeline) AND this request is the
    // simple path: no terminal-prosody shaping, no SSM resume. Everything else falls
    // through to the serial loop below, byte-identical to today.
    if continuous_batch_enabled() && terminal_prosody.is_none() && !resume && !return_hidden {
        if let Some(sched) = batch_scheduler() {
            let (tx, rx) = std::sync::mpsc::channel();
            sched.submit(BatchJob {
                tokens: tokens.clone(),
                max_new_tokens,
                temperature,
                seed: sampling_seed,
                reply: tx,
            });
            match rx.recv() {
                Ok(Ok(generated)) => {
                    let elapsed = t0.elapsed().as_millis();
                    let resp = serde_json::json!({
                        "generated_tokens": generated,
                        "num_new_tokens": generated.len(),
                        "elapsed_ms": elapsed,
                        "vocab_size": station.vocab_size,
                        "hidden_dim": station.hidden_dim,
                    });
                    let _ = req.respond(json_response(resp.to_string(), 200));
                }
                Ok(Err(e)) => {
                    let _ = req.respond(error_response(&format!("continuous-batch: {}", e), 500));
                }
                Err(_) => {
                    let _ =
                        req.respond(error_response("continuous-batch: decode thread gone", 500));
                }
            }
            return;
        }
    }

    // ────────────────────────────────────────────────────────────────────
    // PREFILL: walk the prompt in chunks of <= NATIVE_BATCH_CAPACITY so the
    // KV cache is populated at positions [0, prompt_len). The model's
    // BATCH_CAPACITY only caps a SINGLE forward_range_chunk call; chunking
    // around it lets prompts of any length (up to KV max_seq_len) prefill
    // correctly.
    //
    // Previously this loop fed `all_tokens[-min(len, 8)..]` to
    // forward_range_chunk every step with start_pos=len-8, which silently
    // truncated chat-templated prompts (33+ tokens) to their last 8 tokens
    // and produced garbage like "A1200000" because the KV cache for
    // positions 0..24 was never populated yet RoPE positions started at 25.
    // ────────────────────────────────────────────────────────────────────
    let prompt_len = tokens.len();
    // Gemma turn/eos stop ids: 1 = <eos>, 106 = <end_of_turn>. The hardcoded
    // 2/151643 EOS check below is Llama/Qwen-specific.
    let is_gemma = {
        let p = station.pipeline.lock().unwrap();
        matches!(&*p, ServingPipeline::Gemma(_))
    };
    // Reset recurrent state for SSM / RWKV (no-op for Llama/Gemma KV prefill).
    // Skipped on the resume path: the caller restored the recurrent state via
    // /ssm-state/load and we must continue from it, not wipe it.
    if !resume {
        let mut p = station.pipeline.lock().unwrap();
        p.reset_for_new_request();
    }
    // Sovereign-sieve KEY (SSM path): arm final-hidden capture BEFORE prefill so
    // the LAST prompt token's post-norm residual lands in the pipeline's
    // `captured_final` for `return_hidden`. No-op for the transformer (captures
    // unconditionally) and for archs lacking the hook. Armed after the reset so
    // the flag survives into the prefill forwards.
    if return_hidden {
        let mut p = station.pipeline.lock().unwrap();
        p.set_capture_hidden(true);
    }
    // Whether this station is the batched-prefill Llama/mistral path. The
    // Llama branch (NativeLlamaPipeline) prefills the whole prompt through
    // batched GEMM (one weight fetch+dequant per block, reused across all
    // prompt rows) instead of the per-token `forward_one` loop — ~0.134s/tok
    // for an 840-token prompt is ~110s of weight-cache thrash that batching
    // collapses. gemma/mamba/rwkv/qwen keep their existing per-token path.
    let is_llama = {
        let p = station.pipeline.lock().unwrap();
        matches!(&*p, ServingPipeline::Llama(_))
    };
    // Only the Mamba (pure-SSM) path participates in the prefix-state cache.
    // Its recurrent state is O(1) and fully summarizes the prefix, so a captured
    // boundary state is exactly restorable. Other archs keep the untouched path.
    let is_mamba = {
        let p = station.pipeline.lock().unwrap();
        matches!(&*p, ServingPipeline::Mamba(_))
    };
    // Mamba-2 (SSD, codestral) specifically — the only arch with a batched
    // (chunked) prefill. Distinct from is_mamba, which also covers Mamba-1 /
    // falcon-mamba (whose scan has no SSD-duality chunk form here).
    let is_mamba2 = {
        let p = station.pipeline.lock().unwrap();
        matches!(&*p, ServingPipeline::Mamba(pipe) if pipe.config.arch == "mamba2")
    };

    // ── SSM PREFIX-STATE RESTORE + SKIP (MOONSHINE_SSM_PREFIX_CACHE) ─────────
    // Before prefilling, find the LONGEST cached prefix of THIS prompt whose
    // state we hold, restore that O(1) recurrent state into the pipeline, and
    // start the prefill loop at that boundary — skipping tokens[0..prefill_start].
    // Correctness: the restored conv_buf+ssm_h is byte-identical to what
    // re-prefilling tokens[0..prefill_start] would have produced (SSM state is a
    // pure function of the token prefix; no positional KV to reconcile), so the
    // continuation from prefill_start is bit-identical to a full prefill. A
    // 64-bit hash match is confirmed by a full token byte-compare before use;
    // any mismatch or restore error falls through to prefill_start = 0 (safe).
    // Gated to: flag on, Mamba arch, fresh prefill (start_pos==0, not resume).
    let mut prefill_start = 0usize;
    if ssm_prefix_cache_enabled() && is_mamba && !resume && start_pos == 0 && prompt_len > 0 {
        let chunk = ssm_prefix_chunk();
        // Candidate boundaries are the chunk multiples strictly inside the prompt
        // (B < prompt_len): we must still run at least the final token's forward so
        // the pipeline's next-token logits buffer is repopulated — the logits are
        // NOT part of the recurrent-state blob, only conv_buf+ssm_h are.
        let mut chosen: Option<usize> = None;
        {
            let cache = station.ssm_prefix_cache.lock().unwrap();
            let mut b = chunk;
            while b < prompt_len {
                let ph = fnv1a_64_tokens(&tokens[..b]);
                if let Some(entry) = cache.peek(ph, b) {
                    // Collision guard: only accept when the prefix tokens match
                    // exactly (hash agreement alone is not trusted). Scanning
                    // ascending means the last hit wins = the LONGEST prefix.
                    if entry.tokens.as_slice() == &tokens[..b] {
                        chosen = Some(b);
                    }
                }
                b += chunk;
            }
        }
        // Re-fetch the winning entry WITH an LRU touch (peek above did not touch),
        // then restore. Recompute the hash from the chosen boundary length.
        if let Some(boundary) = chosen {
            let ph = fnv1a_64_tokens(&tokens[..boundary]);
            let entry = {
                let mut cache = station.ssm_prefix_cache.lock().unwrap();
                cache.get(ph, boundary)
            };
            if let Some(entry) = entry {
                // Double-check tokens under the (now dropped) lock's returned value.
                if entry.tokens.as_slice() == &tokens[..boundary] {
                    let mut p = station.pipeline.lock().unwrap();
                    if let ServingPipeline::Mamba(pipe) = &mut *p {
                        match restore_mamba_state_body(pipe, &entry.state_bytes) {
                            Ok(_) => {
                                prefill_start = boundary;
                                eprintln!(
                                    "[fat-station] ssm-prefix-cache HIT: restored state at boundary={} (prompt_len={}), skipping {} prefill forwards",
                                    boundary, prompt_len, boundary
                                );
                            }
                            Err(e) => {
                                // Corrupt/mismatched blob → full prefill. Re-reset so
                                // a partially-applied restore can't leak into decode.
                                eprintln!("[fat-station] ssm-prefix-cache restore failed ({e}); full prefill");
                                pipe.reset_states();
                            }
                        }
                    }
                }
            }
        }
    }

    if is_llama {
        // BATCHED PREFILL (Llama/mistral): one call embeds the prompt, runs
        // all layers in BATCH_CAPACITY-token GEMM pieces, populates KV for
        // [0, prompt_len), and leaves the LAST token's next-token logits in
        // the pipeline exactly as the per-token tail would have — so the
        // decode loop below reads `logits_to`/`get_logits` unchanged.
        let fwd = {
            let mut p = station.pipeline.lock().unwrap();
            std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                p.as_llama_mut()
                    .expect("is_llama checked above")
                    .prefill_chunk(&tokens, 0)
            }))
        };
        match fwd {
            Ok(Ok(())) => {}
            Ok(Err(e)) => {
                let _ = req.respond(error_response(
                    &format!("batched prefill (llama): {}", e),
                    500,
                ));
                return;
            }
            Err(e) => {
                let _ = req.respond(error_response(
                    &format!("batched prefill panic (llama): {:?}", panic_payload(&e)),
                    500,
                ));
                return;
            }
        }
    } else if ssm_chunked_prefill_enabled() && is_mamba2 && !return_hidden && prompt_len > prefill_start {
        // CHUNKED (batched-projection) PREFILL for Mamba-2 SSD (codestral). The
        // in/out_proj GEMVs are batched into one GEMM per chunk (dequant-once /
        // launch-collapse), while the conv + SSD scan stay the exact per-token
        // recurrence — so the resulting state + last-token logits are bit-identical
        // to the per-token loop below. Starts at `prefill_start` (any restored SSM
        // prefix-state boundary carries in via the recurrent state). The per-token
        // prefix-cache CAPTURE is intentionally NOT run here (documented on
        // `prefill_chunked`); the RESTORE above still applies. Gated off when
        // `return_hidden` so the capture_hidden hook keeps the per-token path.
        let vocab = station.vocab_size;
        let sub_start = prefill_start;
        let fwd = {
            let mut p = station.pipeline.lock().unwrap();
            std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                if let ServingPipeline::Mamba(pipe) = &mut *p {
                    MAMBA_RWKV_LOGITS.with(|cell| {
                        let mut buf = cell.borrow_mut();
                        buf.clear();
                        buf.resize(vocab, 0.0);
                        pipe.prefill_chunked(&tokens[sub_start..], &mut buf);
                    });
                }
            }))
        };
        if let Err(e) = fwd {
            let _ = req.respond(error_response(
                &format!("chunked prefill panic (mamba2): {:?}", panic_payload(&e)),
                500,
            ));
            return;
        }
    } else {
        // PREFILL via the arch-dispatched forward (Gemma KV prefill,
        // Mamba/RWKV recurrent step), populating the next-token logits.
        // `.skip(prefill_start)` resumes from a restored SSM prefix-state
        // boundary (0 = full prefill for every non-Mamba/cache-miss path).
        let ssm_capture = ssm_prefix_cache_enabled() && is_mamba && !resume && start_pos == 0;
        let capture_chunk = ssm_prefix_chunk();
        for (i, &tok) in tokens.iter().enumerate().skip(prefill_start) {
            // On the resume path, feed tokens at their true continuation
            // positions (start_pos + i) so the restored recurrent state advances
            // from where the checkpoint left off.
            let fwd_pos = start_pos + i;
            let fwd = {
                let mut p = station.pipeline.lock().unwrap();
                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                    p.generate_forward_one(tok as usize, fwd_pos)
                }))
            };
            match fwd {
                Ok(Ok(_)) => {}
                Ok(Err(e)) => {
                    let _ = req.respond(error_response(
                        &format!("prefill forward @ pos {}: {}", fwd_pos, e),
                        500,
                    ));
                    return;
                }
                Err(e) => {
                    let _ = req.respond(error_response(
                        &format!("prefill forward panic @ pos {}: {:?}", fwd_pos, panic_payload(&e)),
                        500,
                    ));
                    return;
                }
            }
            // ── SSM PREFIX-STATE CAPTURE ────────────────────────────────────
            // After processing token i, the recurrent state summarizes
            // tokens[0..i+1]. At each chunk boundary (boundary = i+1 divisible by
            // chunk) snapshot the O(1) state (the same bytes `/ssm-state/save`
            // emits) under (prefix_hash(tokens[0..boundary]), boundary), together
            // with the exact prefix tokens for the collision guard. Boundaries up
            // to and INCLUDING prompt_len are stored — a boundary == this prompt's
            // length is a usable prefix for a FUTURE longer prompt.
            if ssm_capture {
                let boundary = i + 1;
                if boundary % capture_chunk == 0 {
                    let blob = {
                        let mut p = station.pipeline.lock().unwrap();
                        match &mut *p {
                            ServingPipeline::Mamba(pipe) => {
                                // Pull the GPU-resident SSD state back to host FIRST:
                                // the Mamba-2 hot path leaves `ssm_h` stale (per-token
                                // mirror gated off), so serializing without this would
                                // snapshot a zeroed state → a future HIT restores no
                                // memory and decodes a garbled, non-terminating tail.
                                pipe.sync_gpu_state_to_host();
                                Some(serialize_mamba_state(pipe))
                            }
                            _ => None,
                        }
                    };
                    if let Some(blob) = blob {
                        let ph = fnv1a_64_tokens(&tokens[..boundary]);
                        let mut cache = station.ssm_prefix_cache.lock().unwrap();
                        // Skip re-inserting an entry we just restored from (same
                        // key already present) to avoid a redundant blob clone.
                        if cache.peek(ph, boundary).is_none() {
                            cache.insert(ph, boundary, tokens[..boundary].to_vec(), blob);
                        }
                    }
                }
            }
        }
    }

    // Sovereign-sieve KEY: capture the LAST prompt token's residual (the semantic key) right
    // after prefill, before the decode loop advances the state. Same accessor /hidden-embed
    // reads; the TAIL (not mean-pooled) matches the validated resonance key. Only when the
    // caller asked (return_hidden) → zero cost on the default path.
    let prompt_hidden: Option<Vec<f32>> = if return_hidden {
        let mut p = station.pipeline.lock().unwrap();
        // Per-arch tail hidden: `get_x_residual()` for the transformer,
        // `captured_final` for the SSM (Mamba) path. `None` when capture didn't
        // run → the response omits `prompt_hidden` (sieve stays reachable:false)
        // rather than shipping a zero-length array the TS treats as garbage.
        let h = p.prompt_hidden_tail();
        p.set_capture_hidden(false); // disarm; the key is captured
        h
    } else {
        None
    };

    // Greedy-decode loop. At step k we have KV populated for
    // positions [0, prompt_len + k); we sample from the last residual,
    // append the chosen token, then run a single-token forward at the next
    // position to produce the residual for step k+1.
    let mut pos_next = start_pos + prompt_len;
    // Hoisted logits scratch: `logits_to` clears + extends, so one Vec
    // amortizes the full-vocab copy buffer across the whole decode instead
    // of re-allocating ~vocab×4 bytes per token under the pipeline mutex.
    let mut logits_vec: Vec<f32> = Vec::new();
    // Same for the temperature-sampling softmax numerators.
    let mut exps_scratch: Vec<f32> = Vec::new();
    for step in 0..max_new_tokens {
        // Next-token logits = the pipeline's logits from the last forward_one
        // (the prefill tail for step 0, or the advance forward for step k>0).
        // Copied out so the immutable get_logits borrow does not collide with the
        // mutable forward_one advance below.
        {
            let p = station.pipeline.lock().unwrap();
            p.logits_to(&mut logits_vec);
        }
        let last_logits: &[f32] = &logits_vec;
        let top_token = if let Some(terminal) = &terminal_prosody {
            let context = TerminalProsodyContext::new(
                step + 1,
                max_new_tokens,
                terminal_tail_state,
                &terminal.sentence_close_token_ids,
                &terminal.stop_token_ids,
            );
            let selection = select_terminal_token(last_logits, &context);
            if selection.pressure.crossed_break && selection.adjusted {
                eprintln!(
                    "[fat-station] terminal-prosody step={}/{} directive={:?} baseline={} selected={} remaining={}",
                    step + 1,
                    max_new_tokens,
                    selection.pressure.directive,
                    selection.baseline_token_id,
                    selection.token_id,
                    selection.pressure.remaining_tokens,
                );
            }
            selection.token_id
        } else if temperature > 0.0 {
            // Temperature sampling: softmax(logits / T), then multinomial draw.
            // Subtract max_logit before exp for numerical stability (standard
            // softmax-with-temperature numerator: exp((l - max) / T)). We then
            // sample by drawing u ∈ [0, sum) and walking the CDF.
            let max_logit = last_logits
                .iter()
                .cloned()
                .fold(f32::NEG_INFINITY, f32::max);
            let inv_t = 1.0_f32 / temperature;
            let mut sum = 0.0_f32;
            exps_scratch.clear();
            exps_scratch.extend(last_logits.iter().map(|&l| {
                let e = ((l - max_logit) * inv_t).exp();
                sum += e;
                e
            }));
            let exps: &[f32] = &exps_scratch;
            // Degenerate fallback: if sum is non-finite or zero (all -inf), fall
            // back to argmax rather than producing NaN-driven garbage.
            if !sum.is_finite() || sum <= 0.0 {
                last_logits
                    .iter()
                    .enumerate()
                    .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
                    .map(|(i, _)| i as u32)
                    .unwrap_or(0)
            } else {
                let u: f32 = match sampling_rng.as_mut() {
                    Some(rng) => rng.f32(),
                    None => fastrand::f32(),
                } * sum;
                let mut cum = 0.0_f32;
                let mut chosen: u32 = (exps.len().saturating_sub(1)) as u32;
                for (i, &e) in exps.iter().enumerate() {
                    cum += e;
                    if cum >= u {
                        chosen = i as u32;
                        break;
                    }
                }
                chosen
            }
        } else {
            last_logits
                .iter()
                .enumerate()
                .max_by(|a, b| a.1.partial_cmp(b.1).unwrap_or(std::cmp::Ordering::Equal))
                .map(|(i, _)| i as u32)
                .unwrap_or(0)
        };

        generated.push(top_token);
        if let Some(terminal) = &terminal_prosody {
            terminal_tail_state = observe_terminal_tail_state(
                top_token,
                &terminal.sentence_close_token_ids,
                &terminal.stop_token_ids,
            );
        }
        // Stop at EOS (token 2 for Llama/TinyLlama, 151643 for Qwen), plus
        // any configured terminal stop token. Stop before advancing the KV
        // cache for an unneeded next token.
        let configured_stop = terminal_prosody
            .as_ref()
            .is_some_and(|p| p.stop_token_ids.contains(&top_token));
        // Gemma: <eos>=1, <end_of_turn>=106.
        let gemma_stop = is_gemma && (top_token == 1 || top_token == 106);
        if top_token == 2 || top_token == 151_643 || gemma_stop || configured_stop {
            break;
        }
        if step + 1 == max_new_tokens {
            break;
        }

        // Advance: a single forward_one at pos_next updates the KV cache AND
        // repopulates self.logits for the next step (same proven path as prefill).
        let fwd = {
            let mut p = station.pipeline.lock().unwrap();
            std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                p.generate_forward_one(top_token as usize, pos_next)
            }))
        };
        match fwd {
            Ok(Ok(_)) => {}
            Ok(Err(e)) => {
                let _ = req.respond(error_response(
                    &format!("decode forward step {} @ pos {}: {}", step, pos_next, e),
                    500,
                ));
                return;
            }
            Err(e) => {
                let _ = req.respond(error_response(
                    &format!(
                        "decode forward panic step {} @ pos {}: {:?}",
                        step,
                        pos_next,
                        panic_payload(&e)
                    ),
                    500,
                ));
                return;
            }
        }
        pos_next += 1;
        let _ = num_layers; // used implicitly
    }

    let elapsed = t0.elapsed().as_millis();
    let mut resp = serde_json::json!({
        "generated_tokens": generated,
        "num_new_tokens": generated.len(),
        "elapsed_ms": elapsed,
        "vocab_size": station.vocab_size,
        "hidden_dim": station.hidden_dim,
    });
    // Attach the semantic key only when requested → default response byte-identical.
    if let Some(h) = prompt_hidden {
        resp["prompt_hidden"] = serde_json::json!(h);
    }
    let _ = req.respond(json_response(resp.to_string(), 200));
}

/// DEBUG isolation endpoint. Runs the EXACT `paris-probe-rknot --dense-only`
/// forward path against THIS (possibly cuda-compiled) binary's loaded pipeline:
/// `reset_states()` then feed the raw request tokens one-by-one through the
/// arch's `forward_one` (via `generate_forward_one`, whose Mamba/RWKV/Hybrid arms
/// are literally `p.forward_one(tok, &mut buf)`), and return the FINAL token's
/// argmax + top-5. It BYPASSES the tokenizer, chat template, `/generate` wrapper,
/// the sampler, terminal-prosody, the amplituhedron/prefix cache, and the
/// continuous-batch scheduler — pure `from_knot(loaded) + forward_one`, mirroring
/// paris-probe-rknot.rs lines ~590-595.
///
/// Purpose: POST `{"tokens":[510,5347,273,6181,310]}` to the DEPLOYED
/// fat-station-cuda and compare its argmax to the non-cuda probe's 7785 ("Paris").
/// - 7785  → this binary's `forward_one` is correct → the bug is in the generate
///           wrapper / tokenizer→forward glue.
/// - other → the cuda BUILD of `forward_one` diverges from the scalar probe → a
///           `#[cfg(feature="cuda")]` branch in model_mamba.rs (the `mat_vec`
///           cuBLAS f32 GEMM at :231 engages when FLUX_GPU_MIN_TOKENS ≤ 1, the
///           `mat_vec_q8` kernel at :280 under MESH_GPU_Q8K, or the S6 scan at
///           :452 under MESH_GPU_SCAN). Toggle those to bisect.
/// TwoTower-Sovereign context-memory hook. Build the frozen pure-SSM "context KV"
/// the diffusion denoiser cross-attends to, from a Mamba pipeline whose
/// `capture_hidden` was armed for the just-completed forward. Emits (see
/// docs/twotower-sovereign-demo.md "Context-summary hook" + gnosis/twotower/
/// prototype.py):
///   Source A — final-layer hidden (`final_hidden`, [hidden]) + the per-layer
///     residual stack strided to ~16 slots (`per_layer_hidden`, [M, hidden]).
///   Source B — the raw S6 recurrent state `ssm_h` mean-pooled over d_inner to a
///     per-layer fingerprint (`ssm_state`, [M, d_state]) — the seq-length-
///     INDEPENDENT pure-SSM state (mirrors /ssm-state/save's `states[l].ssm_h`).
/// Shapes track the LOADED knot's config (mamba-2.8b: hidden=2560; falcon-mamba-7b:
/// hidden=4096). Includes per-slot L2 norms + a finite/nan count so the reply is
/// self-verifying.
fn mamba_context_json(pipe: &MambaPipeline) -> serde_json::Value {
    let hidden = pipe.config.hidden_dim;
    let d_inner = pipe.config.d_inner;
    let d_state = pipe.config.d_state;
    let num_layers = pipe.config.num_layers;
    // Stride the 64-layer stack down to ~16 memory slots (prototype mem_stride).
    let stride = (num_layers / 16).max(1);
    let layer_ids: Vec<usize> = (0..num_layers).step_by(stride).collect();

    let l2 = |v: &[f32]| -> f32 { v.iter().map(|x| x * x).sum::<f32>().sqrt() };
    let count_nonfinite =
        |v: &[f32]| -> usize { v.iter().filter(|x| !x.is_finite()).count() };
    let mut nan_count = 0usize;

    // Source A: final-normed hidden (== get_x_residual for the transformer path).
    let final_hidden: Vec<f32> = pipe.captured_final.clone();
    nan_count += count_nonfinite(&final_hidden);
    let final_hidden_norm = l2(&final_hidden);

    // Source A: strided per-layer residual stack. captured_hidden is the flat
    // [num_layers * hidden] stack for the LAST forwarded token.
    let mut per_layer_hidden: Vec<Vec<f32>> = Vec::with_capacity(layer_ids.len());
    let mut per_layer_hidden_norm: Vec<f32> = Vec::with_capacity(layer_ids.len());
    let have_stack = pipe.captured_hidden.len() >= num_layers * hidden;
    for &lid in &layer_ids {
        let slot: Vec<f32> = if have_stack {
            pipe.captured_hidden[lid * hidden..(lid + 1) * hidden].to_vec()
        } else {
            Vec::new()
        };
        nan_count += count_nonfinite(&slot);
        per_layer_hidden_norm.push(l2(&slot));
        per_layer_hidden.push(slot);
    }

    // Source B: mean-pool the raw S6 state ssm_h over d_inner → [d_state] per
    // (strided) layer. Mamba-1 layout is idx = ch * d_state + s (model_mamba.rs).
    let mut ssm_state: Vec<Vec<f32>> = Vec::with_capacity(layer_ids.len());
    let mut ssm_state_norm: Vec<f32> = Vec::with_capacity(layer_ids.len());
    let pooled_ok = d_inner * d_state > 0;
    for &lid in &layer_ids {
        let h = &pipe.states[lid].ssm_h;
        let mut fp = vec![0.0f32; d_state];
        if pooled_ok && h.len() >= d_inner * d_state {
            for ch in 0..d_inner {
                let base = ch * d_state;
                for (s, fp_s) in fp.iter_mut().enumerate() {
                    *fp_s += h[base + s];
                }
            }
            let inv = 1.0f32 / d_inner as f32;
            for v in fp.iter_mut() {
                *v *= inv;
            }
        } else if h.len() == d_state {
            // Mamba-2 diagonal state is already [d_state].
            fp.copy_from_slice(h);
        }
        nan_count += count_nonfinite(&fp);
        ssm_state_norm.push(l2(&fp));
        ssm_state.push(fp);
    }

    serde_json::json!({
        "final_hidden": final_hidden,
        "per_layer_hidden": per_layer_hidden,
        "ssm_state": ssm_state,
        "layer_ids": layer_ids,
        "shapes": {
            "final_hidden": [hidden],
            "per_layer_hidden": [layer_ids.len(), hidden],
            "ssm_state": [layer_ids.len(), d_state],
            "num_layers": num_layers,
            "hidden_dim": hidden,
            "d_inner": d_inner,
            "d_state": d_state,
            "mem_stride": stride,
        },
        "stats": {
            "final_hidden_norm": final_hidden_norm,
            "per_layer_hidden_norm": per_layer_hidden_norm,
            "ssm_state_norm": ssm_state_norm,
            "nan_count": nan_count,
        },
        "note": "TwoTower-Sovereign frozen pure-SSM context memory (Source A: final+per-layer hidden; Source B: pooled ssm_h). Read-only from the frozen forward.",
    })
}

fn handle_debug_forward(station: &Station, mut req: Request) {
    if !matches!(station.role, Role::Both | Role::Entry) {
        let _ = req.respond(error_response(
            "/debug/forward only available on role=both|entry",
            404,
        ));
        return;
    }
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let json: serde_json::Value = match serde_json::from_slice(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("bad JSON: {}", e), 400));
            return;
        }
    };
    let tokens: Vec<u32> = match json.get("tokens").and_then(|v| v.as_array()) {
        Some(arr) => arr
            .iter()
            .filter_map(|v| v.as_u64().map(|n| n as u32))
            .collect(),
        None => {
            let _ = req.respond(error_response("missing field: tokens (u32 array)", 400));
            return;
        }
    };
    if tokens.is_empty() {
        let _ = req.respond(error_response("tokens must be non-empty", 400));
        return;
    }

    let top_k = json.get("top_k").and_then(|v| v.as_u64()).unwrap_or(5) as usize;
    // TwoTower-Sovereign context hook: when set, ALSO emit the frozen pure-SSM
    // context memory after the forward (Mamba/falcon-mamba only). Additive — the
    // default reply (flag absent) is byte-identical to before.
    let return_context = json
        .get("return_context")
        .and_then(|v| v.as_bool())
        .unwrap_or(false);

    // Fresh sequence, then feed every token through forward_one and read the
    // FINAL logits — no sampling, no advance beyond the prompt. Held under one
    // lock so no concurrent request perturbs the recurrent state mid-scan.
    let t0 = std::time::Instant::now();
    let result: Result<(Vec<f32>, Option<serde_json::Value>), String> = {
        let mut p = station.pipeline.lock().unwrap();
        if return_context && !matches!(&*p, ServingPipeline::Mamba(_)) {
            Err(format!(
                "return_context requires a Mamba/SSM pipeline (falcon-mamba / mamba-2.8b); \
                 this knot is {}",
                p.arch_label()
            ))
        } else {
            // Arm the per-layer + final hidden capture on the Mamba pipe (Source A).
            if return_context {
                if let ServingPipeline::Mamba(pipe) = &mut *p {
                    pipe.capture_hidden = true;
                }
            }
            p.reset_for_new_request();
            let mut err: Option<String> = None;
            for (i, &tok) in tokens.iter().enumerate() {
                let fwd = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                    p.generate_forward_one(tok as usize, i)
                }));
                match fwd {
                    Ok(Ok(())) => {}
                    Ok(Err(e)) => {
                        err = Some(format!("forward_one @ pos {}: {}", i, e));
                        break;
                    }
                    Err(e) => {
                        err = Some(format!(
                            "forward_one panic @ pos {}: {:?}",
                            i,
                            panic_payload(&e)
                        ));
                        break;
                    }
                }
            }
            match err {
                Some(e) => {
                    if let ServingPipeline::Mamba(pipe) = &mut *p {
                        pipe.capture_hidden = false;
                    }
                    Err(e)
                }
                None => {
                    let mut logits = Vec::new();
                    p.logits_to(&mut logits);
                    let ctx = if return_context {
                        if let ServingPipeline::Mamba(pipe) = &mut *p {
                            pipe.capture_hidden = false; // disarm
                            Some(mamba_context_json(pipe))
                        } else {
                            None
                        }
                    } else {
                        None
                    };
                    Ok((logits, ctx))
                }
            }
        }
    };

    let (logits, context) = match result {
        Ok(l) => l,
        Err(e) => {
            let _ = req.respond(error_response(&e, 500));
            return;
        }
    };

    // argmax + top-k (partial sort by logit desc).
    let mut idx: Vec<usize> = (0..logits.len()).collect();
    idx.sort_unstable_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    let argmax = idx.first().copied().unwrap_or(0);
    let top: Vec<serde_json::Value> = idx
        .iter()
        .take(top_k)
        .map(|&i| serde_json::json!({ "token": i, "logit": logits[i] }))
        .collect();
    let nan = logits.iter().filter(|v| !v.is_finite()).count();

    let mut resp = serde_json::json!({
        "argmax": argmax,
        "top": top,
        "num_tokens": tokens.len(),
        "vocab_size": logits.len(),
        "nan_count": nan,
        "arch": station.pipeline.lock().unwrap().arch_label(),
        "elapsed_ms": t0.elapsed().as_millis(),
        "note": "pure forward_one (bypasses tokenizer/template/sampler/cache/generate wrapper)",
    });
    // Attach the frozen pure-SSM context memory only when requested → default
    // response byte-identical (TwoTower-Sovereign P2 context-summary hook).
    if let Some(ctx) = context {
        resp["context"] = ctx;
    }
    let _ = req.respond(json_response(resp.to_string(), 200));
}

fn handle_prompt_feedback(_station: &Station, mut req: Request) {
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let json: serde_json::Value = match serde_json::from_slice(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("bad JSON: {}", e), 400));
            return;
        }
    };
    let resp = match prompt_feedback_response_from_json(&json) {
        Ok(resp) => resp,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let _ = req.respond(json_response(resp.to_string(), 200));
}

fn prompt_feedback_response_from_json(
    json: &serde_json::Value,
) -> Result<serde_json::Value, String> {
    let frames_b64 = json
        .get("frames_base64")
        .and_then(|v| v.as_array())
        .ok_or_else(|| "missing field: frames_base64 (string[])".to_string())?;
    let mut frames = Vec::with_capacity(frames_b64.len());
    for (index, value) in frames_b64.iter().enumerate() {
        let encoded = value
            .as_str()
            .ok_or_else(|| format!("frames_base64[{}] must be a string", index))?;
        let bytes = BASE64_STANDARD
            .decode(encoded)
            .map_err(|e| format!("frames_base64[{}] base64 decode failed: {}", index, e))?;
        let frame: PleromaticFrame = bincode::deserialize(&bytes)
            .map_err(|e| format!("frames_base64[{}] bincode decode failed: {}", index, e))?;
        frames.push(frame);
    }
    let max_frames = json
        .get("max_frames")
        .and_then(|v| v.as_u64())
        .map(|v| v as usize)
        .unwrap_or(3);
    let feedback = thoth_prompt_feedback_from_frames(&frames, max_frames);
    let admission_rejections = feedback
        .admission_rejections
        .iter()
        .map(|rejection| {
            serde_json::json!({
                "frame_kind": rejection.frame_kind.clone(),
                "source_id": rejection.source_id.clone(),
                "sequence": rejection.sequence,
                "reason": rejection.reason.clone(),
                "observed_theorem": rejection.observed_theorem.clone(),
                "expected_theorem": feedback.admissibility_theorem,
                "rejection_residue_theorem": rejection.rejection_residue_theorem,
            })
        })
        .collect::<Vec<_>>();
    Ok(serde_json::json!({
        "context": feedback.render_system_context(),
        "line_count": feedback.lines.len(),
        "theorem": feedback.theorem,
        "admissibility_theorem": feedback.admissibility_theorem,
        "rejection_residue_theorem": feedback.rejection_residue_theorem,
        "accepted_frame_count": feedback.lines.len(),
        "rejected_frame_count": feedback.admission_rejections.len(),
        "admission_rejections": admission_rejections,
        "input_frame_count": frames.len(),
    }))
}

// ─────────────────────────────────────────────────────────────────────
// /tokenize — in-tree smoke tokenizer
//
// The NativeLlamaPipeline owns no tokenizer (the .knot format ships
// weights + config, not vocab/merges). Production tokenization routes
// through `aether-tokenizer-bridge` on the JS side. This handler exists
// to unblock the local Pleromatic Residual Atlas capture pipeline
// (`scripts/capture-and-build-dict.sh`), which drives `/generate` with
// a single fixed prompt and needs a way to convert text → u32 token IDs
// without dragging a `tokenizers` crate into the native binary.
//
// The strategy mirrors `phi3_tokenize_smoke_prompt` in model_phi3.rs:
// a tiny table of canonical prompts with pre-computed Qwen2 BPE token
// IDs. Unknown prompts return 400 with a pointer to the production path.
// IDs were verified against
// `open-source/buleyean-rl/output/gnosis-lean-qwen05/tokenizer.json`
// using huggingface `tokenizers` (BPE-with-ByteLevel pretokenizer).
// ─────────────────────────────────────────────────────────────────────

/// Qwen2 / Qwen2.5 BOS token id (tokenizer.ggml.bos_token_id from the
/// canonical qwen2 tokenizer config). Matches edge-workers
/// `model-onboarding.ts` (`bosToken: 151643`).
const QWEN2_BOS_TOKEN: u32 = 151_643;

/// Smoke-table lookup. Input is normalized (trim + lowercase +
/// whitespace-collapse) before comparison.
fn qwen2_tokenize_smoke_prompt(prompt: &str) -> Option<Vec<u32>> {
    let normalized: String = prompt
        .trim()
        .to_lowercase()
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ");
    match normalized.as_str() {
        // "The capital of France is" — the FIXED_PROMPT used by
        // scripts/capture-and-build-dict.sh. Verified IDs:
        //   785  -> "The"
        //   6722 -> "Ġcapital"
        //   315  -> "Ġof"
        //   9625 -> "ĠFrance"
        //   374  -> "Ġis"
        "the capital of france is" => Some(vec![785, 6722, 315, 9625, 374]),
        // "Hello, world" — basic Qwen2 smoke from
        // `bench-teleportation.rs --tokens 9707,11,1879,151643`.
        // Tokens: 9707 "Hello", 11 ",", 1879 "Ġworld", 151643 EOS.
        // Provided so /tokenize can self-test against an
        // already-shipped reference sequence.
        "hello, world" => Some(vec![9707, 11, 1879]),
        _ => None,
    }
}

/// Lazily-loaded real Qwen2 byte-level BPE encoder, built from the GGUF
/// pointed to by TOKENIZER_GGUF_PATH (the same env var /detokenize uses).
/// `None` once we've decided no usable GGUF is configured, so we don't
/// re-probe the filesystem on every /tokenize request. When present,
/// /tokenize encodes ARBITRARY text; when absent it falls back to the
/// tiny in-tree smoke table (preserving the no-GGUF behavior).
static TOKENIZE_ENCODER: std::sync::OnceLock<Option<Qwen2BpeEncoder>> = std::sync::OnceLock::new();

fn tokenize_encoder() -> Option<&'static Qwen2BpeEncoder> {
    TOKENIZE_ENCODER
        .get_or_init(|| {
            let path = std::env::var("TOKENIZER_GGUF_PATH").ok()?;
            let p = std::path::Path::new(&path);
            if !p.exists() {
                eprintln!(
                    "[fat-station] TOKENIZER_GGUF_PATH={:?} does not exist; /tokenize falls back to smoke table",
                    path
                );
                return None;
            }
            match Qwen2BpeEncoder::from_gguf(p) {
                Ok(enc) => {
                    eprintln!(
                        "[fat-station] /tokenize: loaded real Qwen2 BPE encoder from {:?} (vocab={}, merges={})",
                        path, enc.vocab_size, enc.merge_count
                    );
                    Some(enc)
                }
                Err(e) => {
                    eprintln!(
                        "[fat-station] TOKENIZER_GGUF_PATH={:?} encoder load failed ({}); /tokenize falls back to smoke table",
                        path, e
                    );
                    None
                }
            }
        })
        .as_ref()
}

fn handle_tokenize(station: &Station, mut req: Request) {
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let json: serde_json::Value = match serde_json::from_slice(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("bad JSON: {}", e), 400));
            return;
        }
    };
    let text: &str = match json.get("text").and_then(|v| v.as_str()) {
        Some(s) => s,
        None => {
            let _ = req.respond(error_response("missing field: text (string)", 400));
            return;
        }
    };
    // Qwen2's tokenizer config has `bos_token: null`; chat templates do
    // not prepend BOS to user prompts. Default to false; callers that
    // want a BOS-prefixed sequence (e.g. for the `/generate` prefill of
    // a base / non-chat completion) can opt in.
    let add_bos = json
        .get("add_bos")
        .and_then(|v| v.as_bool())
        .unwrap_or(false);

    // Encode. Two paths, in priority order:
    //
    //   1. Real Qwen2 byte-level BPE encoder from TOKENIZER_GGUF_PATH — the
    //      SAME GGUF /detokenize loads. Encodes ARBITRARY text (this is
    //      what unlocks the Skymesh "ask the mesh anything" box). The
    //      pipeline lock is held while encoding to keep the wire contract
    //      symmetric with the other handlers (and so a future
    //      pipeline.tokenize() is a drop-in), even though the encoder is
    //      table-driven and does not touch the kernel.
    //
    //   2. When no GGUF is configured, fall back to the tiny in-tree smoke
    //      table (preserving the original no-GGUF behavior exactly).
    let source: &str;
    let tokens_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        let _p = station.pipeline.lock().unwrap();
        if let Some(enc) = tokenize_encoder() {
            // (Ok(ids) or Err(msg)) for the real encoder.
            Ok(enc.encode(text))
        } else {
            // Smoke-table fallback: Some(ids) or None (unknown prompt).
            Err(qwen2_tokenize_smoke_prompt(text))
        }
    }));

    let mut tokens = match tokens_result {
        // Real encoder path.
        Ok(Ok(Ok(t))) => {
            source = "gguf-bpe";
            t
        }
        Ok(Ok(Err(e))) => {
            let _ = req.respond(error_response(
                &format!("tokenize failed (gguf BPE encoder): {}", e),
                500,
            ));
            return;
        }
        // Smoke-table fallback path.
        Ok(Err(Some(t))) => {
            source = "smoke-table";
            t
        }
        Ok(Err(None)) => {
            let _ = req.respond(error_response(
                &format!(
                    "text {:?} not in the in-tree smoke tokenizer's table (no TOKENIZER_GGUF_PATH set; set it to a Qwen2 GGUF for full-vocab encode, or POST {{\"tokens\": [u32,...]}} directly to /generate)",
                    text
                ),
                400,
            ));
            return;
        }
        Err(e) => {
            let _ = req.respond(error_response(
                &format!("tokenize panicked: {:?}", panic_payload(&e)),
                500,
            ));
            return;
        }
    };
    if add_bos {
        tokens.insert(0, QWEN2_BOS_TOKEN);
    }

    eprintln!(
        "[fat-station] /tokenize text={:?} add_bos={} source={} -> {} tokens",
        text,
        add_bos,
        source,
        tokens.len()
    );
    let count = tokens.len();
    let resp = serde_json::json!({
        "tokens": tokens,
        "count": count,
        "add_bos": add_bos,
    });
    let _ = req.respond(json_response(resp.to_string(), 200));
}

// ─────────────────────────────────────────────────────────────────────
// /detokenize — symmetric inverse of /tokenize
//
// The .knot weight format ships no vocab, so detokenization needs a
// vocab source. Two are supported, in priority order:
//
//   1. A GGUF carrying `tokenizer.ggml.tokens` (the Qwen2 BPE vocab),
//      pointed to by the TOKENIZER_GGUF_PATH env var. This mirrors
//      `distributed-inference-host/src/bin/openai-server.ts`, which
//      loads the same metadata via `qwen-tokenizer.ts`. With this set,
//      /detokenize maps the full 151,936-entry vocab and is the
//      production-faithful path. A Qwen2.5-family GGUF works for any
//      Qwen2 .knot (qwen-coder-7b, qwen-0.5b, …): the tokenizer is
//      shared across the family; only the unused top padding rows
//      (151,936..152,064) differ, and real generations never emit them.
//
//   2. When TOKENIZER_GGUF_PATH is unset / unreadable / lacks tokens,
//      /detokenize falls back to a tiny reverse smoke table — exactly
//      the inverse of `qwen2_tokenize_smoke_prompt`, plus the canonical
//      Paris next-token (12095 -> " Paris"). Any token id outside that
//      set returns 400 with a pointer to TOKENIZER_GGUF_PATH. This
//      keeps the handler honest: it never fabricates a vocab.
//
// Decode algorithm (GGUF path) matches openai-server's QwenTokenizer:
// concatenate the raw token pieces (skipping special <|...|> tokens),
// then reverse the GPT-2/Qwen byte-level mapping (each unicode char in
// the piece maps back to one source byte; the resulting byte stream is
// UTF-8 decoded). "Ġ" -> 0x20 (space), "Ċ" -> 0x0a (newline), etc.
// ─────────────────────────────────────────────────────────────────────

/// Lazily-loaded detokenizer vocab. `None` once we've decided no GGUF is
/// usable (so we don't re-probe the filesystem on every request).
static DETOK_VOCAB: std::sync::OnceLock<Option<DetokVocab>> = std::sync::OnceLock::new();

struct DetokVocab {
    /// id -> raw token piece (byte-level encoded, GGUF order).
    id_to_token: Vec<String>,
    /// char (from the GPT-2 byte-map) -> source byte. 256 entries.
    byte_decoder: HashMap<char, u8>,
    source: String,
}

/// Build the GPT-2 / Qwen byte-level unicode map. Identical to
/// `buildByteMaps()` in qwen-tokenizer.ts. Returns char -> byte.
fn gpt2_byte_decoder() -> HashMap<char, u8> {
    let mut bytes: Vec<u32> = Vec::with_capacity(256);
    for b in ('!' as u32)..=('~' as u32) {
        bytes.push(b);
    }
    for b in 0xa1u32..=0xac {
        bytes.push(b);
    }
    for b in 0xaeu32..=0xff {
        bytes.push(b);
    }
    let mut chars: Vec<u32> = bytes.clone();
    let mut next = 0u32;
    for b in 0u32..256 {
        if !bytes.contains(&b) {
            bytes.push(b);
            chars.push(256 + next);
            next += 1;
        }
    }
    let mut decoder = HashMap::with_capacity(256);
    for (i, &b) in bytes.iter().enumerate() {
        if let Some(c) = char::from_u32(chars[i]) {
            decoder.insert(c, b as u8);
        }
    }
    decoder
}

/// Read just `tokenizer.ggml.tokens` (the vocab string array) out of a
/// GGUF file's metadata. Pure byte-walk over the GGUF KV section — no
/// extra crate. Mirrors the GGUFMetadataReader in qwen-tokenizer.ts.
fn read_gguf_tokens(path: &std::path::Path) -> Result<Vec<String>, String> {
    use std::io::{Read, Seek, SeekFrom};
    const GGUF_MAGIC: u32 = 0x4655_4747; // "GGUF" little-endian
                                         // GGUF metadata value type codes.
    const T_UINT8: u32 = 0;
    const T_INT8: u32 = 1;
    const T_UINT16: u32 = 2;
    const T_INT16: u32 = 3;
    const T_UINT32: u32 = 4;
    const T_INT32: u32 = 5;
    const T_FLOAT32: u32 = 6;
    const T_BOOL: u32 = 7;
    const T_STRING: u32 = 8;
    const T_ARRAY: u32 = 9;
    const T_UINT64: u32 = 10;
    const T_INT64: u32 = 11;
    const T_FLOAT64: u32 = 12;

    let mut f = std::fs::File::open(path).map_err(|e| format!("open gguf: {}", e))?;

    fn rd_u32(f: &mut std::fs::File) -> Result<u32, String> {
        let mut b = [0u8; 4];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u32::from_le_bytes(b))
    }
    fn rd_u64(f: &mut std::fs::File) -> Result<u64, String> {
        let mut b = [0u8; 8];
        f.read_exact(&mut b).map_err(|e| e.to_string())?;
        Ok(u64::from_le_bytes(b))
    }
    fn rd_string(f: &mut std::fs::File) -> Result<String, String> {
        let len = rd_u64(f)? as usize;
        let mut buf = vec![0u8; len];
        f.read_exact(&mut buf).map_err(|e| e.to_string())?;
        Ok(String::from_utf8_lossy(&buf).into_owned())
    }
    fn scalar_size(t: u32) -> Result<u64, String> {
        Ok(match t {
            T_UINT8 | T_INT8 | T_BOOL => 1,
            T_UINT16 | T_INT16 => 2,
            T_UINT32 | T_INT32 | T_FLOAT32 => 4,
            T_UINT64 | T_INT64 | T_FLOAT64 => 8,
            other => return Err(format!("unsupported gguf scalar type {}", other)),
        })
    }
    fn skip_value(f: &mut std::fs::File, t: u32) -> Result<(), String> {
        match t {
            T_STRING => {
                let len = rd_u64(f)?;
                f.seek(SeekFrom::Current(len as i64))
                    .map_err(|e| e.to_string())?;
            }
            T_ARRAY => {
                let at = rd_u32(f)?;
                let al = rd_u64(f)?;
                if at == T_STRING {
                    for _ in 0..al {
                        let len = rd_u64(f)?;
                        f.seek(SeekFrom::Current(len as i64))
                            .map_err(|e| e.to_string())?;
                    }
                } else {
                    let sz = scalar_size(at)?;
                    f.seek(SeekFrom::Current((sz * al) as i64))
                        .map_err(|e| e.to_string())?;
                }
            }
            scalar => {
                let sz = scalar_size(scalar)?;
                f.seek(SeekFrom::Current(sz as i64))
                    .map_err(|e| e.to_string())?;
            }
        }
        Ok(())
    }

    if rd_u32(&mut f)? != GGUF_MAGIC {
        return Err("not a GGUF file (bad magic)".to_string());
    }
    let version = rd_u32(&mut f)?;
    if version < 2 {
        return Err(format!("unsupported GGUF version {}", version));
    }
    let _n_tensors = rd_u64(&mut f)?;
    let n_kv = rd_u64(&mut f)?;

    for _ in 0..n_kv {
        let key = rd_string(&mut f)?;
        let vtype = rd_u32(&mut f)?;
        if key == "tokenizer.ggml.tokens" {
            if vtype != T_ARRAY {
                return Err("tokenizer.ggml.tokens is not an array".to_string());
            }
            let at = rd_u32(&mut f)?;
            if at != T_STRING {
                return Err("tokenizer.ggml.tokens is not a string array".to_string());
            }
            let al = rd_u64(&mut f)? as usize;
            let mut tokens = Vec::with_capacity(al);
            for _ in 0..al {
                tokens.push(rd_string(&mut f)?);
            }
            return Ok(tokens);
        }
        skip_value(&mut f, vtype)?;
    }
    Err("GGUF metadata has no tokenizer.ggml.tokens".to_string())
}

/// Load (once) the detokenizer vocab from TOKENIZER_GGUF_PATH, if set.
/// Returns `None` if unset/unreadable — caller then uses the smoke
/// fallback.
fn detok_vocab() -> Option<&'static DetokVocab> {
    DETOK_VOCAB
        .get_or_init(|| {
            let path = std::env::var("TOKENIZER_GGUF_PATH").ok()?;
            let p = std::path::Path::new(&path);
            if !p.exists() {
                eprintln!(
                    "[fat-station] TOKENIZER_GGUF_PATH={:?} does not exist; /detokenize falls back to smoke table",
                    path
                );
                return None;
            }
            match read_gguf_tokens(p) {
                Ok(tokens) => {
                    eprintln!(
                        "[fat-station] /detokenize: loaded {} vocab tokens from {:?}",
                        tokens.len(),
                        path
                    );
                    Some(DetokVocab {
                        id_to_token: tokens,
                        byte_decoder: gpt2_byte_decoder(),
                        source: path,
                    })
                }
                Err(e) => {
                    eprintln!(
                        "[fat-station] TOKENIZER_GGUF_PATH={:?} read failed ({}); /detokenize falls back to smoke table",
                        path, e
                    );
                    None
                }
            }
        })
        .as_ref()
}

/// True for tokens that should be dropped from decoded text (Qwen
/// special tokens). Mirrors QwenTokenizer.isSpecialToken in
/// qwen-tokenizer.ts.
fn detok_is_special(token: &str) -> bool {
    token.starts_with("<|")
        || token == "<tool_call>"
        || token == "</tool_call>"
        || token.starts_with("[PAD")
}

/// Reverse the GPT-2 byte map for one token piece, appending raw bytes
/// to `out`. Unknown chars (shouldn't happen for GGUF pieces) are
/// UTF-8-encoded as a fallback, matching qwen-tokenizer.ts byteDecode.
fn detok_byte_decode(piece: &str, decoder: &HashMap<char, u8>, out: &mut Vec<u8>) {
    for c in piece.chars() {
        match decoder.get(&c) {
            Some(&b) => out.push(b),
            None => {
                let mut buf = [0u8; 4];
                out.extend_from_slice(c.encode_utf8(&mut buf).as_bytes());
            }
        }
    }
}

/// Inverse of `qwen2_tokenize_smoke_prompt` (per-token), extended with
/// the canonical Paris next-token. Only used when no GGUF vocab is
/// available. Returns `None` for any id outside the recognized set.
fn qwen2_detokenize_smoke_token(id: u32) -> Option<&'static str> {
    match id {
        785 => Some("The"),
        6722 => Some(" capital"),
        315 => Some(" of"),
        9625 => Some(" France"),
        374 => Some(" is"),
        // PARIS FACT: [785,6722,315,9625,374] -> 12095 (" Paris").
        12095 => Some(" Paris"),
        9707 => Some("Hello"),
        11 => Some(","),
        1879 => Some(" world"),
        QWEN2_BOS_TOKEN => Some(""), // BOS decodes to empty string
        _ => None,
    }
}

fn handle_detokenize(_station: &Station, mut req: Request) {
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let json: serde_json::Value = match serde_json::from_slice(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("bad JSON: {}", e), 400));
            return;
        }
    };
    // Accept both "token_ids" (spec) and "tokens" (symmetry with the
    // /tokenize response field) so callers can round-trip either.
    let arr = json
        .get("token_ids")
        .or_else(|| json.get("tokens"))
        .and_then(|v| v.as_array());
    let arr = match arr {
        Some(a) => a,
        None => {
            let _ = req.respond(error_response(
                "missing field: token_ids (array of u32)",
                400,
            ));
            return;
        }
    };
    let mut ids: Vec<u32> = Vec::with_capacity(arr.len());
    for v in arr {
        match v.as_u64() {
            Some(n) if n <= u32::MAX as u64 => ids.push(n as u32),
            _ => {
                let _ = req.respond(error_response(
                    &format!("token_ids must be u32 values (got {})", v),
                    400,
                ));
                return;
            }
        }
    }

    let (text, source) = if let Some(vocab) = detok_vocab() {
        // Full-vocab GGUF path.
        let mut bytes: Vec<u8> = Vec::new();
        for &id in &ids {
            let piece = match vocab.id_to_token.get(id as usize) {
                Some(p) => p,
                None => {
                    let _ = req.respond(error_response(
                        &format!(
                            "token id {} out of range for vocab of size {} ({})",
                            id,
                            vocab.id_to_token.len(),
                            vocab.source
                        ),
                        400,
                    ));
                    return;
                }
            };
            if detok_is_special(piece) {
                continue;
            }
            detok_byte_decode(piece, &vocab.byte_decoder, &mut bytes);
        }
        (
            String::from_utf8_lossy(&bytes).into_owned(),
            vocab.source.clone(),
        )
    } else {
        // Smoke-table fallback. Honest about the gap: any id outside the
        // tiny table is a hard 400 pointing at TOKENIZER_GGUF_PATH.
        let mut s = String::new();
        for &id in &ids {
            match qwen2_detokenize_smoke_token(id) {
                Some(piece) => s.push_str(piece),
                None => {
                    let _ = req.respond(error_response(
                        &format!(
                            "token id {} not in the in-tree smoke detokenizer table (set TOKENIZER_GGUF_PATH to a Qwen2 GGUF for full-vocab detokenization; recognized smoke ids: 11,374,315,785,1879,6722,9625,9707,12095,{})",
                            id, QWEN2_BOS_TOKEN
                        ),
                        400,
                    ));
                    return;
                }
            }
        }
        (s, "smoke-table".to_string())
    };

    eprintln!(
        "[fat-station] /detokenize {} ids (source={}) -> {:?}",
        ids.len(),
        source,
        text
    );
    let resp = serde_json::json!({
        "text": text,
        "count": ids.len(),
        "source": source,
    });
    let _ = req.respond(json_response(resp.to_string(), 200));
}

fn panic_payload(p: &Box<dyn std::any::Any + Send>) -> String {
    if let Some(s) = p.downcast_ref::<String>() {
        s.clone()
    } else if let Some(s) = p.downcast_ref::<&'static str>() {
        s.to_string()
    } else {
        "<non-string panic payload>".to_string()
    }
}

